  for (int UE_id=UE_info->list.head; UE_id>=0; UE_id=UE_info->list.next[UE_id]) {
    for (int i=0; i<UE_info->numactiveCCs[UE_id]; i++) {
      int CC_id = UE_info->ordered_CCids[i][UE_id];
